# --- SOAPAction Spoofing Prevention Middleware ---

# Mapping of SOAPAction headers to the expected operation names that should
# appear in the SOAP body.  This is the core anti-spoofing mechanism: even if
# an attacker sends a crafted SOAPAction header that points to one operation,
# the middleware verifies that the SOAP body actually contains a call to that
# same operation.  A mismatch causes the request to be rejected *before* any
# business logic executes.

SOAP_ACTION_TO_OPERATION = {
    '"urn:financial.services/getBalance"': "getBalance",
    '"urn:financial.services/transferFunds"': "transferFunds",
    '"urn:financial.services/getAccountInfo"': "getAccountInfo",
    # Also accept without quotes (some clients send it that way)
    'urn:financial.services/getBalance': "getBalance",
    'urn:financial.services/transferFunds': "transferFunds",
    'urn:financial.services/getAccountInfo': "getAccountInfo",
}


class SOAPActionValidationMiddleware:
    """WSGI middleware that prevents SOAPAction spoofing.

    It performs two checks:
    1. The SOAPAction header must map to a known operation.
    2. The operation name found inside the SOAP XML body must match the
       operation indicated by the SOAPAction header.

    This prevents an attacker from sending SOAPAction: getBalance while the
    body actually contains a transferFunds call (or vice-versa).
    """

    def __init__(self, app):
        self.app = app

    def __call__(self, environ, start_response):
        soap_action = environ.get("HTTP_SOAPACTION", "").strip()

        # If no SOAPAction header, let spyne handle it (it will route by body)
        if soap_action:
            # 1. Validate SOAPAction is a known value
            expected_operation = SOAP_ACTION_TO_OPERATION.get(soap_action)
            if expected_operation is None:
                logger.warning(
                    "Rejected request with unknown SOAPAction: %s", soap_action
                )
                return self._fault_response(
                    start_response,
                    "Client",
                    f"Unknown SOAPAction: {soap_action}",
                )

            # 2. Peek at the SOAP body to find the actual operation element
            try:
                # Read body; we need to make it re-readable for spyne
                body_bytes = environ["wsgi.input"].read()
                # Replace wsgi.input so downstream can read it again
                from io import BytesIO
                environ["wsgi.input"] = BytesIO(body_bytes)

                body_operation = self._extract_operation_from_body(body_bytes)

                if body_operation is None:
                    logger.warning(
                        "Could not determine operation from SOAP body"
                    )
                    return self._fault_response(
                        start_response,
                        "Client",
                        "Could not determine operation from SOAP body",
                    )

                if body_operation != expected_operation:
                    logger.warning(
                        "SOAPAction spoofing detected! SOAPAction indicates "
                        "'%s' but body contains '%s'",
                        expected_operation,
                        body_operation,
                    )
                    return self._fault_response(
                        start_response,
                        "Client",
                        f"SOAPAction mismatch: header says '{expected_operation}' "
                        f"but body contains '{body_operation}'. Request rejected.",
                    )

                logger.info(
                    "SOAPAction validation passed for operation: %s",
                    expected_operation,
                )

            except Exception as e:
                logger.error("Error during SOAPAction validation: %s", e)
                return self._fault_response(
                    start_response,
                    "Server",
                    "Internal error during request validation",
                )

        return self.app(environ, start_response)

    def _extract_operation_from_body(self, body_bytes):
        """Parse the SOAP envelope and extract the operation name from the Body."""
        import xml.etree.ElementTree as ET

        try:
            root = ET.fromstring(body_bytes)
        except ET.ParseError:
            return None

        # Find the SOAP Body element (handle both SOAP 1.1 and 1.2 namespaces)
        soap_ns_candidates = [
            "http://schemas.xmlsoap.org/soap/envelope/",  # SOAP 1.1
            "http://www.w3.org/2003/05/soap-envelope",     # SOAP 1.2
        ]

        body_element = None
        for ns in soap_ns_candidates:
            body_element = root.find(f"{{{ns}}}Body")
            if body_element is not None:
                break

        if body_element is None:
            return None

        # The first child of Body is the operation element
        for child in body_element:
            # Strip namespace to get local name
            tag = child.tag
            if "}" in tag:
                local_name = tag.split("}", 1)[1]
            else:
                local_name = tag
            return local_name

        return None

    def _fault_response(self, start_response, fault_code, fault_string):
        """Return a SOAP Fault response."""
        fault_xml = f"""<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:{fault_code}</faultcode>
      <faultstring>{fault_string}</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>""".encode("utf-8")

        start_response(
            "500 Internal Server Error",
            [
                ("Content-Type", "text/xml; charset=utf-8"),
                ("Content-Length", str(len(fault_xml))),
            ],
        )
        return [fault_xml]


# --- Input Validation Helpers ---

def validate_account_id(account_id):
    """Validate account ID format and existence."""
    if not account_id or not isinstance(account_id, str):
        raise Fault(faultcode="Client", faultstring="Account ID is required")
    
    account_id = account_id.strip()
    
    # Validate format (alphanumeric, reasonable length)
    if not account_id.isalnum() or len(account_id) > 20:
        raise Fault(
            faultcode="Client",
            faultstring="Invalid account ID format",
        )
    
    if account_id not in ACCOUNTS_DB:
        raise Fault(
            faultcode="Client",
            faultstring=f"Account {account_id} not found",
        )
    
    return account_id


def validate_amount(amount):
    """Validate transfer amount."""
    if amount is None:
        raise Fault(faultcode="Client", faultstring="Amount is required")
    if not isinstance(amount, (int, float)):
        raise Fault(faultcode="Client", faultstring="Amount must be numeric")
    if amount <= 0:
        raise Fault(
            faultcode="Client",
            faultstring="Amount must be positive",
        )
    if amount > 1_000_000:
        raise Fault(
            faultcode="Client",
            faultstring="Amount exceeds maximum transfer limit of 1,000,000",
        )
    # Round to 2 decimal places
    return round(amount, 2)


# --- Service Definition ---

class FinancialService(Service):
    """Financial Services SOAP API."""

    @srpc(Unicode, _returns=BalanceResult, _operation_name="getBalance",
          _soap_action="urn:financial.services/getBalance")
    def getBalance(account_id):
        """Retrieve the current balance for a given account."""
        logger.info("getBalance called for account: %s", account_id)

        account_id = validate_account_id(account_id)
        account = ACCOUNTS_DB[account_id]

        if not account["is_active"]:
            raise Fault(
                faultcode="Client",
                faultstring=f"Account {account_id} is inactive",
            )

        result = BalanceResult()
        result.account_id = account["account_id"]
        result.balance = account["balance"]
        result.currency = account["currency"]
        result.as_of = datetime.utcnow()

        logger.info(
            "Balance for %s: %s %s",
            account_id,
            account["balance"],
            account["currency"],
        )
        return result

    @srpc(
        Unicode, Unicode, Float,
        _returns=TransferResult,
        _operation_name="transferFunds",
        _soap_action="urn:financial.services/transferFunds",
    )
    def transferFunds(from_account_id, to_account_id, amount):
        """Transfer funds between two accounts."""
        logger.info(
            "transferFunds called: %s -> %s, amount: %s",
            from_account_id,
            to_account_id,
            amount,
        )

        from_account_id = validate_account_id(from_account_id)
        to_account_id = validate_account_id(to_account_id)
        amount = validate_amount(amount)

        if from_account_id == to_account_id:
            raise Fault(
                faultcode="Client",
                faultstring="Source and destination accounts must be different",
            )

        from_account = ACCOUNTS_DB[from_account_id]
        to_account = ACCOUNTS_DB[to_account_id]

        if not from_account["is_active"]:
            raise Fault(
                faultcode="Client",
                faultstring=f"Source account {from_account_id} is inactive",
            )

        if not to_account["is_active"]:
            raise Fault(
                faultcode="Client",
                faultstring=f"Destination account {to_account_id} is inactive",
            )

        if from_account["balance"] < amount:
            raise Fault(
                faultcode="Client",
                faultstring="Insufficient funds",
            )

        # Execute transfer
        from_account["balance"] = round(from_account["balance"] - amount, 2)
        to_account["balance"] = round(to_account["balance"] + amount, 2)

        txn_id = generate_transaction_id()

        result = TransferResult()
        result.transaction_id = txn_id
        result.status = "SUCCESS"
        result.message = f"Successfully transferred {amount} {from_account['currency']} from {from_account_id} to {to_account_id}"
        result.timestamp = datetime.utcnow()
        result.from_account = from_account_id
        result.to_account = to_account_id
        result.amount = amount
        result.remaining_balance = from_account["balance"]

        logger.info("Transfer successful: %s", txn_id)
        return result

    @srpc(Unicode, _returns=AccountInfo, _operation_name="getAccountInfo",
          _soap_action="urn:financial.services/getAccountInfo")
    def getAccountInfo(account_id):
        """Retrieve full account information."""
        logger.info("getAccountInfo called for account: %s", account_id)

        account_id = validate_account_id(account_id)
        account = ACCOUNTS_DB[account_id]

        result = AccountInfo()
        result.account_id = account["account_id"]
        result.account_holder = account["account_holder"]
        result.account_type = account["account_type"]
        result.balance = account["balance"]
        result.currency = account["currency"]
        result.created_date = account["created_date"]
        result.is_active = account["is_active"]

        logger.info("Account info retrieved for %s", account_id)
        return result


